const email = $input.first().json;

// Determiner le tenantId depuis l'adresse destinataire
// Pour le moment, mapping statique email -> tenantId
const TENANT_MAP = {
  'direction@talosprimes.com': 'efbf3d9e-6ccc-44a3-ad41-dc4093ecc227'
};
const toAddr = (email.to || '').toLowerCase();
let tenantId = null;
for (const [addr, tid] of Object.entries(TENANT_MAP)) {
  if (toAddr.includes(addr)) { tenantId = tid; break; }
}

return [{ json: {
  id: email.id || null,
  threadId: email.threadId || null,
  from: email.from || '',
  to: email.to || '',
  subject: email.subject || '(sans objet)',
  date: email.date || new Date().toISOString(),
  snippet: email.snippet || '',
  textPlain: (email.textPlain || '').substring(0, 1000),
  labels: email.labelIds || [],
  hasAttachments: (email.attachments || []).length > 0,
  tenantId: tenantId,
  action: 'received'
} }];

